            "example": "",
            "overviewMarkdown": "# 🔴 Hard: Byte-Pair Encoding (BPE)\n\nImplement a simple **BPE tokenizer** — the foundation of GPT/LLaMA tokenization.\n\n### Signature\n```python\nclass SimpleBPE:\n    def __init__(self): ...\n    def train(self, corpus: list[str], num_merges: int): ...\n    def encode(self, text: str) -> list[str]: ...\n```\n\n### Algorithm (training)\n1. Split each word into characters + `</w>` end marker\n2. Count all adjacent pairs across the corpus\n3. Merge the most frequent pair into a single token\n4. Repeat for `num_merges` iterations",
            "solutionOverviewMarkdown": "# Solution: Byte-Pair Encoding (BPE)\n\nReference solution.",
            "starterCode": "# ✏️ YOUR IMPLEMENTATION HERE\n\nclass SimpleBPE:\n    def __init__(self):\n        self.merges = []\n\n    def train(self, corpus, num_merges):\n        pass  # iteratively find & merge most frequent pairs\n\n    def encode(self, text):\n        pass  # apply learned merges to split text",
            "exampleCode": "",
            "submitCode": "# ✅ SUBMIT\nfrom torch_judge import check\ncheck('bpe')",
            "referenceCode": "# ✅ SOLUTION\n\nclass SimpleBPE:\n    def __init__(self):\n        self.merges = []\n\n    def train(self, corpus, num_merges):\n        vocab = {}\n        for word in corpus:\n            symbols = tuple(word) + ('</w>',)\n            vocab[symbols] = vocab.get(symbols, 0) + 1\n        self.merges = []\n        for _ in range(num_merges):\n            pairs = {}\n            for word, freq in vocab.items():\n                for i in range(len(word) - 1):\n                    pair = (word[i], word[i + 1])\n                    pairs[pair] = pairs.get(pair, 0) + freq\n            if not pairs:\n                break\n            best = max(pairs, key=pairs.get)\n            self.merges.append(best)\n            new_vocab = {}\n            for word, freq in vocab.items():\n                new_word = []\n                i = 0\n                while i < len(word):\n                    if i < len(word) - 1 and (word[i], word[i + 1]) == best:\n                        new_word.append(word[i] + word[i + 1])\n                        i += 2\n                    else:\n                        new_word.append(word[i])\n                        i += 1\n                new_vocab[tuple(new_word)] = freq\n            vocab = new_vocab\n\n    def encode(self, text):\n        all_tokens = []\n        for word in text.split():\n            symbols = list(word) + ['</w>']\n            for a, b in self.merges:\n                i = 0\n                while i < len(symbols) - 1:\n                    if symbols[i] == a and symbols[i + 1] == b:\n                        symbols = symbols[:i] + [a + b] + symbols[i + 2:]\n                    else:\n                        i += 1\n            all_tokens.extend(symbols)\n        return all_tokens",
